export interface Lead {
  id: string;
  name: string;
  rating: string;
  reviews: string;
  address: string;
  phone: string;
  mapsUrl: string;
}

export interface SearchParams {
  business_type: string;
  location: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Lead, SearchParams } from "../types";

const API_KEY = process.env.API_KEY || "";

export const fetchLeads = async (params: SearchParams, currentLeadsCount: number = 0): Promise<Lead[]> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    Encuentra 15 prospectos de negocios reales en México siguiendo estos criterios:
    Tipo de negocio: ${params.business_type}
    Ubicación: ${params.location}, México.

    Genera una lista detallada que incluya exactamente:
    - Nombre del Negocio
    - Calificación (Estrellas)
    - Número de Reseñas
    - Dirección Completa
    - Número de Teléfono
    - URL de Google Maps (si está disponible)

    IMPORTANTE: Los negocios deben ser reales y estar ubicados en México. 
    Devuelve la información en un formato de bloque de código JSON estrictamente válido, sin texto adicional, que sea una lista de objetos con las llaves: 
    "name", "rating", "reviews", "address", "phone", "mapsUrl".

    Si no encuentras el dato exacto, coloca "N/A".
    Asegúrate de que sean resultados diferentes a los ${currentLeadsCount} que ya podrías haber listado.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        // Note: grounding results might not strictly follow JSON output settings sometimes,
        // so we prompt for JSON and parse it carefully.
      },
    });

    const text = response.text || "";

    // Attempt to extract JSON from the response text
    const jsonMatch = text.match(/\[\s*{[\s\S]*}\s*\]/);
    if (jsonMatch) {
      const leads: any[] = JSON.parse(jsonMatch[0]);
      return leads.map((l, index) => ({
        id: `${Date.now()}-${index}`,
        name: l.name || "N/A",
        rating: l.rating || "N/A",
        reviews: l.reviews || "N/A",
        address: l.address || "N/A",
        phone: l.phone || "N/A",
        mapsUrl: l.mapsUrl || "N/A",
      }));
    }

    return [];
  } catch (error) {
    console.error("Error fetching leads:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { SearchParams } from '../types';

interface SearchFormProps {
  onSearch: (params: SearchParams) => void;
  isLoading: boolean;
}

export const SearchForm: React.FC<SearchFormProps> = ({ onSearch, isLoading }) => {
  const [params, setParams] = useState<SearchParams>({
    business_type: '',
    location: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!params.business_type || !params.location) return;
    onSearch(params);
  };

  return (
    <form 
      onSubmit={handleSubmit} 
      className="bg-white p-6 rounded-xl shadow-lg border border-purple-100 mb-8"
    >
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <label className="block text-sm font-semibold text-purple-900 mb-2">
            Tipo de Negocio
          </label>
          <input
            type="text"
            placeholder="Ej: Ferreterías, Vidrieras, Transporte..."
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-purple-600 focus:border-transparent outline-none transition-all"
            value={params.business_type}
            onChange={(e) => setParams({ ...params, business_type: e.target.value })}
            required
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-purple-900 mb-2">
            Ubicación (México)
          </label>
          <input
            type="text"
            placeholder="Ej: Ciudad de México, Estado de México, Guadalajara..."
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-purple-600 focus:border-transparent outline-none transition-all"
            value={params.location}
            onChange={(e) => setParams({ ...params, location: e.target.value })}
            required
          />
        </div>
      </div>
      <button
        type="submit"
        disabled={isLoading}
        className={`mt-6 w-full py-3 px-6 rounded-lg text-white font-bold text-lg transition-all ${
          isLoading 
          ? 'bg-purple-400 cursor-not-allowed' 
          : 'bg-purple-700 hover:bg-purple-800 active:scale-[0.98] shadow-md'
        }`}
      >
        {isLoading ? (
          <span className="flex items-center justify-center">
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Extrayendo Leads...
          </span>
        ) : 'Extraer Leads'}
      </button>
    </form>
  );
};

