            <th className="px-6 py-4 text-left text-xs font-bold text-white uppercase tracking-wider">Reseñas</th>
            <th className="px-6 py-4 text-left text-xs font-bold text-white uppercase tracking-wider">Dirección</th>
            <th className="px-6 py-4 text-left text-xs font-bold text-white uppercase tracking-wider">Teléfono</th>
