        <tbody className="bg-white divide-y divide-gray-100">
          {leads.map((lead) => (
            <tr key={lead.id} className="hover:bg-purple-50 transition-colors">
              <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-gray-900">{lead.name}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                <div className="flex items-center">
                  <span className="text-yellow-500 mr-1">★</span>
                  {lead.rating}
                </div>
              </td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">{lead.reviews}</td>
              <td className="px-6 py-4 text-sm text-gray-600 max-w-xs truncate">{lead.address}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-purple-700 font-medium">{lead.phone}</td>
              <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                {lead.mapsUrl !== 'N/A' ? (
                  <a 
                    href={lead.mapsUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-purple-600 hover:text-purple-800 underline font-medium"
                  >
                    Ver Mapa
                  </a>
                ) : 'Sin Link'}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { SearchForm } from './components/SearchForm';
import { ResultsTable } from './components/ResultsTable';
import { fetchLeads } from './services/geminiService';
import { Lead, SearchParams } from './types';

const App: React.FC = () => {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [currentParams, setCurrentParams] = useState<SearchParams | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = async (params: SearchParams) => {
    setIsLoading(true);
    setError(null);
    setLeads([]);
    setCurrentParams(params);

    try {
      const data = await fetchLeads(params);
      if (data.length === 0) {
        setError("No se encontraron resultados para esta búsqueda. Intenta con otros términos.");
      } else {
        setLeads(data);
      }
    } catch (err) {
      setError("Ocurrió un error al extraer los datos. Por favor intenta de nuevo.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLoadMore = async () => {
    if (!currentParams) return;
    setIsLoading(true);
    setError(null);

    try {
      const moreData = await fetchLeads(currentParams, leads.length);
      if (moreData.length === 0) {
        setError("No se encontraron más resultados adicionales.");
      } else {
        // Simple deduplication based on name and address
        const existingKeys = new Set(leads.map(l => `${l.name}-${l.address}`));
        const filteredNew = moreData.filter(l => !existingKeys.has(`${l.name}-${l.address}`));
        setLeads(prev => [...prev, ...filteredNew]);
      }
    } catch (err) {
      setError("Error al cargar más resultados.");
    } finally {
      setIsLoading(false);
    }
  };

  const downloadCSV = () => {
    if (leads.length === 0) return;

    const headers = ["Nombre", "Calificación", "Reseñas", "Dirección", "Teléfono", "Google Maps URL"];
    const rows = leads.map(l => [
      `"${l.name}"`,
      `"${l.rating}"`,
      `"${l.reviews}"`,
      `"${l.address}"`,
      `"${l.phone}"`,
      `"${l.mapsUrl}"`
    ]);

    const csvContent = [headers.join(","), ...rows.map(e => e.join(","))].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `leads_${currentParams?.business_type}_${currentParams?.location}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {/* Header */}
      <header className="bg-purple-900 text-white py-12 px-4 shadow-xl mb-10">
        <div className="max-w-6xl mx-auto flex flex-col items-center text-center">
          <div className="bg-white/10 p-3 rounded-full mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <h1 className="text-4xl font-bold tracking-tight mb-2">LeadScrapper MX</h1>
          <p className="text-purple-200 text-lg max-w-2xl font-medium">
            Automatiza la extracción de leads comerciales en México con inteligencia artificial.
          </p>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4">
        {/* Search Section */}
        <SearchForm onSearch={handleSearch} isLoading={isLoading} />

        {/* Error Notification */}
        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-r-lg shadow-sm">
            <div className="flex">
              <div className="flex-shrink-0">
                <svg className="h-5 w-5 text-red-400" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                </svg>
              </div>
              <div className="ml-3">
                <p className="text-sm text-red-700 font-medium">{error}</p>
              </div>
            </div>
          </div>
        )}

        {/* Results Section */}
        {leads.length > 0 && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
              <h2 className="text-2xl font-bold text-purple-900">
                Resultados Obtenidos ({leads.length})
              </h2>
              <button
                onClick={downloadCSV}
                className="flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2 rounded-lg font-semibold shadow-md transition-all active:scale-95"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
                Descargar CSV
              </button>
            </div>

            <ResultsTable leads={leads} />

            <div className="flex justify-center mt-8">
              <button
                onClick={handleLoadMore}
                disabled={isLoading}
                className="bg-purple-100 text-purple-700 hover:bg-purple-200 border-2 border-purple-200 px-8 py-3 rounded-full font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isLoading ? "Cargando..." : "Cargar Más Resultados"}
              </button>
            </div>
          </div>
        )}

        {/* Empty State */}
        {!isLoading && leads.length === 0 && !error && (
          <div className="text-center py-20 bg-white rounded-xl shadow-inner border-2 border-dashed border-gray-200">
            <div className="text-gray-400 mb-4">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <h3 className="text-xl font-semibold text-gray-500">No hay datos para mostrar</h3>
            <p className="text-gray-400">Ingresa el tipo de negocio y ciudad para comenzar la extracción.</p>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-gray-200 pt-8 pb-4 text-center">
        <p className="text-gray-500 text-sm">
          &copy; {new Date().getFullYear()} LeadScrapper MX - Senior Fullstack Engineering Demo
        </p>
      </footer>
    </div>
  );
};

export default App;
